#include<bits/stdc++.h>
using namespace std;
int lst[5001],d[5001];
int c[5001],s[5001];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
        s[i]=s[i-1]+c[i];
    }
    for(int l=1;l<=n;l++)
    {
        for(int i=1;i+l-1<=n;i++)
        {
            d[i]=s[i+l-1]-s[i-1]-min(lst[i+1],lst[i]);
        }
        memcpy(lst,d,sizeof(d));
    }
    printf("%d",d[1]);
    return 0;
}
